export interface Coordinates {
  lat: number;
  lng: number;
}

export interface LocationInfo extends Coordinates {
  name: string;
  address?: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  SEARCHING = 'SEARCHING',
  CONFIRMING = 'CONFIRMING',
  TRACKING = 'TRACKING',
  ALARM_TRIGGERED = 'ALARM_TRIGGERED',
}

export interface AlarmConfig {
  target: LocationInfo;
  radius: number; // in meters
  audioBase64: string | null;
}

import { Coordinates } from '../types';

/**
 * Calculates the distance between two coordinates in meters using the Haversine formula.
 */
export const calculateDistance = (coord1: Coordinates, coord2: Coordinates): number => {
  const R = 6371e3; // Earth radius in meters
  const lat1 = (coord1.lat * Math.PI) / 180;
  const lat2 = (coord2.lat * Math.PI) / 180;
  const deltaLat = ((coord2.lat - coord1.lat) * Math.PI) / 180;
  const deltaLng = ((coord2.lng - coord1.lng) * Math.PI) / 180;

  const a =
    Math.sin(deltaLat / 2) * Math.sin(deltaLat / 2) +
    Math.cos(lat1) * Math.cos(lat2) * Math.sin(deltaLng / 2) * Math.sin(deltaLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c;
};

export const formatDistance = (meters: number): string => {
  if (meters < 1000) {
    return `${Math.round(meters)}m`;
  }
  return `${(meters / 1000).toFixed(2)}km`;
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocationInfo } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findLocation = async (query: string): Promise<LocationInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the geographic coordinates (latitude and longitude) for: "${query}". Return the result in JSON format with lat, lng, name, and a short address.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER },
          lng: { type: Type.NUMBER },
          name: { type: Type.STRING },
          address: { type: Type.STRING },
        },
        required: ["lat", "lng", "name"],
      },
    },
  });

  if (!response.text) {
    throw new Error("Failed to resolve location");
  }

  return JSON.parse(response.text) as LocationInfo;
};

export const generateAlarmAudio = async (locationName: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Wake up! You are arriving at ${locationName}. Don't miss your stop!` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Energetic voice
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    throw new Error("Failed to generate audio");
  }
  return base64Audio;
};

import React, { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Circle, useMap, Popup } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates, LocationInfo } from '../types';

// Fix for default Leaflet markers in React
const iconUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png";
const iconRetinaUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png";
const shadowUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png";

const DefaultIcon = L.icon({
  iconUrl,
  iconRetinaUrl,
  shadowUrl,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  tooltipAnchor: [16, -28],
  shadowSize: [41, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

interface MapDisplayProps {
  currentLocation: Coordinates | null;
  targetLocation: LocationInfo | null;
  radius: number;
}

const MapUpdater: React.FC<{ center: Coordinates }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo([center.lat, center.lng], map.getZoom());
  }, [center, map]);
  return null;
};

const MapDisplay: React.FC<MapDisplayProps> = ({ currentLocation, targetLocation, radius }) => {
  // Default to London if no location
  const center = currentLocation || targetLocation || { lat: 51.505, lng: -0.09 };

  return (
    <MapContainer 
      center={[center.lat, center.lng]} 
      zoom={13} 
      scrollWheelZoom={true}
      className="h-full w-full rounded-xl z-0"
    >
      <TileLayer
        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
      />

      {targetLocation && (
        <>
          <Marker position={[targetLocation.lat, targetLocation.lng]}>
             <Popup>{targetLocation.name}</Popup>
          </Marker>
          <Circle 
            center={[targetLocation.lat, targetLocation.lng]} 
            pathOptions={{ fillColor: 'red', color: 'red' }} 
            radius={radius} 
          />
        </>
      )}

      {currentLocation && (
        <>
          <Marker 
            position={[currentLocation.lat, currentLocation.lng]}
            icon={L.divIcon({
              className: 'bg-blue-500 rounded-full border-2 border-white shadow-lg',
              iconSize: [16, 16],
              iconAnchor: [8, 8]
            })}
          />
          <MapUpdater center={currentLocation} />
        </>
      )}
    </MapContainer>
  );
};

export default MapDisplay;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapPin, Navigation, Bell, Search, StopCircle, Volume2, AlertCircle } from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
import { findLocation, generateAlarmAudio } from './services/gemini';
import { calculateDistance, formatDistance } from './utils/geo';
import { AppStatus, LocationInfo, AlarmConfig, Coordinates } from './types';
import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);

  // Initialize Audio Context on user interaction
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          console.error("Geolocation error:", error);
          setLocationError("Unable to access location. Please enable GPS permissions.");
        },
        { enableHighAccuracy: true, maximumAge: 10000, timeout: 5000 }
      );
    } else {
      setLocationError("Geolocation is not supported by this browser.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, []);

  // Distance Tracking Logic
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20); // Keep last 20 points
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
  }, [currentLocation, status, alarmConfig]);

  // Wake Lock for mobile
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {
      console.log('Wake Lock error:', err);
    }
  };

  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.log('Wake lock release error', err);
      }
    }
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setStatus(AppStatus.SEARCHING);
    try {
      const location = await findLocation(query);

      // Generate voice preview immediately to have it ready
      const audioBase64 = await generateAlarmAudio(location.name);

      setAlarmConfig({
        target: location,
        radius: 500, // Default 500m
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("Could not find that location. Please try again.");
      setStatus(AppStatus.IDLE);
    }
  };

  const startTracking = async () => {
    initAudio();
    await requestWakeLock();
    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;

    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }

      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);

      // Loop the alarm
      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) {
               // Simple loop interval would be better handled by looping source if possible, 
               // but for a short speech clip, re-triggering with a delay is fine.
               // However, `loop = true` on source repeats the buffer seamlessly.
            }
        };
        source.loop = true; // Loop the "Wake Up" speech
        audioSourceRef.current = source;
      };

      play();
    } catch (e) {
      console.error("Audio playback failed", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] px-6">
      <div className="bg-blue-100 p-4 rounded-full mb-6">
        <MapPin className="w-12 h-12 text-blue-600" />
      </div>
      <h1 className="text-3xl font-bold text-gray-900 mb-2">NapNav</h1>
      <p className="text-gray-500 text-center mb-8 max-w-xs">
        Sleep on your commute. We'll wake you up when you're close.
      </p>

      <form onSubmit={handleSearch} className="w-full max-w-md relative">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Where are you going?"
          className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-gray-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-sm"
        />
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />
        <button 
            type="submit" 
            disabled={!query}
            className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl font-medium disabled:opacity-50 hover:bg-blue-700 transition-colors"
        >
            Go
        </button>
      </form>

      {locationError && (
        <div className="mt-6 flex items-center gap-2 text-red-500 bg-red-50 px-4 py-2 rounded-lg">
          <AlertCircle className="w-5 h-5" />
          <span className="text-sm font-medium">{locationError}</span>
        </div>
      )}
    </div>
  );

  const renderSearching = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh]">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
      <p className="text-gray-600 font-medium">Asking Gemini to find coordinates...</p>
    </div>
  );

  const renderConfirming = () => (
    <div className="flex flex-col h-screen bg-gray-50">
      <div className="h-1/2 w-full relative">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        <button 
            onClick={() => setStatus(AppStatus.IDLE)}
            className="absolute top-4 left-4 bg-white/90 p-2 rounded-full shadow-lg z-[400]"
        >
            <AlertCircle className="w-6 h-6 text-gray-700" />
        </button>
      </div>

      <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
        <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

        <h2 className="text-2xl font-bold text-gray-900 mb-1">{alarmConfig?.target.name}</h2>
        <p className="text-gray-500 text-sm mb-6">{alarmConfig?.target.address}</p>

        <div className="bg-blue-50 p-4 rounded-2xl mb-6">
            <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-blue-800">Wake-up Radius</span>
                <span className="text-sm font-bold text-blue-900">{formatDistance(alarmConfig?.radius || 500)}</span>
            </div>
            <input 
                type="range" 
                min="100" 
                max="2000" 
                step="100"
                value={alarmConfig?.radius}
                onChange={(e) => setAlarmConfig(prev => prev ? ({...prev, radius: Number(e.target.value)}) : null)}
                className="w-full h-2 bg-blue-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
        </div>

        <button 
            onClick={startTracking}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
        >
            <Bell className="w-6 h-6" />
            Start Alarm
        </button>
      </div>
    </div>
  );

  const renderTracking = () => (
    <div className="flex flex-col h-screen bg-black text-white relative">
      <div className="absolute top-0 left-0 w-full h-1/2 opacity-50">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        {/* Overlay to dim map for focus */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black pointer-events-none z-[401]" />
      </div>

      <div className="relative z-10 flex flex-col h-full mt-[30vh]">
         <div className="flex-1 px-8 flex flex-col justify-end pb-12">
            <div className="mb-2 flex items-center gap-2 text-blue-400">
                <Navigation className="w-5 h-5 animate-pulse" />
                <span className="text-sm tracking-widest uppercase font-semibold">Tracking Location</span>
            </div>

            <div className="text-7xl font-mono font-bold tracking-tighter mb-2">
                {currentDistance !== null ? formatDistance(currentDistance) : '...'}
            </div>
            <p className="text-gray-400 text-lg mb-8">
                to {alarmConfig?.target.name}
            </p>

            <div className="h-32 w-full mb-8">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={distanceHistory}>
                        <YAxis domain={['auto', 'auto']} hide />
                        <Line 
                            type="monotone" 
                            dataKey="distance" 
                            stroke="#3b82f6" 
                            strokeWidth={3} 
                            dot={false}
                            isAnimationActive={false}
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancel Alarm
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">WAKE UP!</h1>
      <p className="text-xl opacity-90 text-center mb-12">You have arrived at {alarmConfig?.target.name}</p>

      <button 
          onClick={stopTracking}
          className="w-full max-w-sm bg-white text-red-600 py-6 rounded-3xl text-2xl font-bold shadow-xl active:scale-95 transition-transform"
      >
          I'm Awake!
      </button>
    </div>
  );

  return (
    <div className="min-h-screen bg-white font-sans antialiased">
      {status === AppStatus.IDLE && renderIdle()}
      {status === AppStatus.SEARCHING && renderSearching()}
      {status === AppStatus.CONFIRMING && renderConfirming()}
      {status === AppStatus.TRACKING && renderTracking()}
      {status === AppStatus.ALARM_TRIGGERED && renderAlarm()}
    </div>
  );
};

export default App;

