import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocationInfo, Coordinates } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findLocation = async (query: string): Promise<LocationInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the geographic coordinates (latitude and longitude) for: "${query}". Return the result in JSON format with lat, lng, name, and a short address.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER },
          lng: { type: Type.NUMBER },
          name: { type: Type.STRING },
          address: { type: Type.STRING },
        },
        required: ["lat", "lng", "name"],
      },
    },
  });

  if (!response.text) {
    throw new Error("Failed to resolve location");
  }

  return JSON.parse(response.text) as LocationInfo;
};

export const getPlaceSuggestions = async (query: string, userLocation: Coordinates | null): Promise<string[]> => {
  const context = userLocation 
    ? `The user is currently at latitude ${userLocation.lat}, longitude ${userLocation.lng}. Bias results strictly to be near this location.` 
    : '';

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Autocomplete suggestions for location search. User input: "${query}". ${context} Return a JSON array of 5 distinct place names or addresses that match. Keep them concise.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });

  if (!response.text) return [];
  try {
    return JSON.parse(response.text) as string[];
  } catch (e) {
    return [];
  }
};

export const generateAlarmAudio = async (locationName: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Wake up! You are arriving at ${locationName}. Don't miss your stop!` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Energetic voice
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    throw new Error("Failed to generate audio");
  }
  return base64Audio;
};

