        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          console.log("Location updated:", newLocation);
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          console.error(`Geolocation Error (Code ${error.code}):`, error.message);
          let msg = "Unable to access location.";
          switch (error.code) {
            case error.PERMISSION_DENIED:
              msg = "Location permission denied. Please enable location access in your browser settings.";
              break;
            case error.POSITION_UNAVAILABLE:
              msg = "Location unavailable. Please check your GPS signal.";
              break;
            case error.TIMEOUT:
              msg = "Location request timed out. Please move to an open area.";
              break;
            default:
              msg = `Location error: ${error.message}`;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: true, 
          maximumAge: 10000, 
          timeout: 20000 
        }
      );
    } else {
      setLocationError("Geolocation is not supported by this browser.");
