    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;

    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }

      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);

      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) {
               // loop handles repetition
            }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };

      play();
    } catch (e) {
      console.error("Audio playback failed", e);
    }
  };

  const stopAlarmSound = () => {
