      </div>

      <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
        <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

