                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancel Alarm
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">WAKE UP!</h1>
      <p className="text-xl opacity-90 text-center mb-12">You have arrived at {alarmConfig?.target.name}</p>

