import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocationInfo, Coordinates } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findLocation = async (query: string): Promise<LocationInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the geographic coordinates (latitude and longitude) for: "${query}". Return the result in JSON format with lat, lng, name, and a short address. Ensure the address is in Spanish if possible.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER },
          lng: { type: Type.NUMBER },
          name: { type: Type.STRING },
          address: { type: Type.STRING },
        },
        required: ["lat", "lng", "name"],
      },
    },
  });

  if (!response.text) {
    throw new Error("No se pudo resolver la ubicación");
  }

  return JSON.parse(response.text) as LocationInfo;
};

export const getPlaceSuggestions = async (query: string, userLocation: Coordinates | null): Promise<string[]> => {
  const context = userLocation 
    ? `The user is currently at latitude ${userLocation.lat}, longitude ${userLocation.lng}. You MUST prioritize places geographically close to this location. Ignore places on other continents unless explicitly typed.` 
    : '';

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Autocomplete suggestions for location search in Spanish. User input: "${query}". ${context} Return a JSON array of 5 distinct place names or addresses that match. Keep them concise and relevant to the local context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });

  if (!response.text) return [];
  try {
    return JSON.parse(response.text) as string[];
  } catch (e) {
    return [];
  }
};

export const generateAlarmAudio = async (locationName: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `¡Despierta! Estás llegando a ${locationName}. ¡No pierdas tu parada!` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Energetic voice works well for alarms
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    throw new Error("Falló la generación de audio");
  }
  return base64Audio;
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapPin, Navigation, Bell, Search, StopCircle, Volume2, AlertCircle, RefreshCw, Loader2, ArrowLeft, X } from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
