import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [useHighAccuracy, setUseHighAccuracy] = useState(true); // New state for fallback logic

  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const debounceRef = useRef<number | null>(null);

  // Initialize Audio Context on user interaction
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }

      console.log(`Iniciando observador de geolocalización. Alta Precisión: ${useHighAccuracy}`);

      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          console.log("Ubicación actualizada:", newLocation);
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          console.warn(`Error de Geolocalización (Código ${error.code}):`, error.message);

          // FALLBACK LOGIC: If high accuracy times out, try low accuracy
          if (error.code === 3 /* TIMEOUT */ && useHighAccuracy) {
             console.log("Tiempo de espera agotado en alta precisión. Cambiando a baja precisión.");
             setLocationError("Señal GPS débil. Cambiando a ubicación por red...");
             setUseHighAccuracy(false); // This triggers re-effect with enableHighAccuracy: false
             return;
          }

          let msg = "No se puede acceder a la ubicación.";
          switch (error.code) {
            case 1: // PERMISSION_DENIED
              msg = "Permiso de ubicación denegado. Actívalo en la configuración de tu navegador.";
              break;
            case 2: // POSITION_UNAVAILABLE
              msg = "Ubicación no disponible. Verifica tu señal GPS.";
              break;
            case 3: // TIMEOUT
              msg = "Tiempo de espera agotado. Muévete a un área abierta.";
              break;
            default:
              msg = `Error de ubicación: ${error.message}`;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: useHighAccuracy, 
          maximumAge: 10000, 
          timeout: 30000 // 30s timeout
        }
      );
    } else {
      setLocationError("Tu navegador no soporta geolocalización.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [useHighAccuracy]);

  // Autocomplete Debounce Logic
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (query.trim().length > 2 && status === AppStatus.IDLE) {
      setIsSuggesting(true);
      debounceRef.current = window.setTimeout(async () => {
        try {
          const results = await getPlaceSuggestions(query, currentLocation);
          setSuggestions(results);
          setShowSuggestions(true);
        } catch (e) {
          console.error("Falló el autocompletado", e);
        } finally {
          setIsSuggesting(false);
        }
      }, 500); // 500ms debounce
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsSuggesting(false);
    }

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [query, currentLocation, status]);

  // Distance Tracking Logic
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20); // Keep last 20 points
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
