      setAlarmConfig({
        target: location,
        radius: 500, 
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("No pudimos encontrar ese lugar. Inténtalo de nuevo.");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(query);
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    executeSearch(suggestion);
  };

  const startTracking = async () => {
    initAudio();
    await requestWakeLock();
    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    setQuery(''); // Clear query on reset
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;

    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }

      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);

      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) {
               // loop handles repetition
            }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };

      play();
    } catch (e) {
      console.error("Fallo en reproducción de audio", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] px-6">
      <div className="bg-blue-100 p-4 rounded-full mb-6">
        <MapPin className="w-12 h-12 text-blue-600" />
      </div>
      <h1 className="text-3xl font-bold text-gray-900 mb-2">NapNav</h1>
      <p className="text-gray-500 text-center mb-8 max-w-xs">
        Duerme en tu viaje. Te despertaremos cuando estés cerca.
      </p>

      <div className="w-full max-w-md relative group">
        <form onSubmit={handleSearch} className="w-full relative z-20">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
            placeholder="¿A dónde vas?"
            className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-gray-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-sm"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />

          {isSuggesting ? (
