            >
              <RefreshCw className="w-3 h-3" /> Reintentar GPS
            </button>
        </div>
      )}
    </div>
  );

  const renderSearching = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] relative">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
      <p className="text-gray-600 font-medium text-center px-4">Consultando a Gemini para localizar el destino...</p>

      <button 
        onClick={() => setStatus(AppStatus.IDLE)}
        className="mt-8 flex items-center gap-2 text-gray-500 hover:text-gray-800 bg-gray-100 px-4 py-2 rounded-full transition-colors"
      >
        <X className="w-4 h-4" /> Cancelar
      </button>
    </div>
  );

  const renderConfirming = () => (
    <div className="flex flex-col h-screen bg-gray-50">
      <div className="h-1/2 w-full relative">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        <button 
            onClick={() => setStatus(AppStatus.IDLE)}
            className="absolute top-4 left-4 bg-white/95 p-3 rounded-full shadow-lg z-[400] hover:bg-gray-100 transition-colors"
            aria-label="Volver atrás"
        >
            <ArrowLeft className="w-6 h-6 text-gray-800" />
        </button>
      </div>

      <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
        <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

        <h2 className="text-2xl font-bold text-gray-900 mb-1">{alarmConfig?.target.name}</h2>
        <p className="text-gray-500 text-sm mb-6">{alarmConfig?.target.address}</p>

        <div className="bg-blue-50 p-4 rounded-2xl mb-6">
            <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-blue-800">Radio de Alarma</span>
                <span className="text-sm font-bold text-blue-900">{formatDistance(alarmConfig?.radius || 500)}</span>
            </div>
            <input 
                type="range" 
                min="100" 
                max="2000" 
                step="100"
                value={alarmConfig?.radius}
                onChange={(e) => setAlarmConfig(prev => prev ? ({...prev, radius: Number(e.target.value)}) : null)}
                className="w-full h-2 bg-blue-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
            <p className="text-xs text-blue-400 mt-2 text-center">Te avisaremos cuando estés a esta distancia.</p>
        </div>

        <div className="flex gap-3">
             <button 
                onClick={() => setStatus(AppStatus.IDLE)}
                className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-2xl text-lg font-bold hover:bg-gray-200 transition-colors"
            >
                Cancelar
            </button>
            <button 
                onClick={startTracking}
                className="flex-[2] bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
            >
                <Bell className="w-6 h-6" />
                Iniciar
            </button>
        </div>
      </div>
    </div>
  );

  const renderTracking = () => (
    <div className="flex flex-col h-screen bg-black text-white relative">
      <div className="absolute top-0 left-0 w-full h-1/2 opacity-50">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        {/* Overlay to dim map for focus */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black pointer-events-none z-[401]" />
      </div>

      <div className="relative z-10 flex flex-col h-full mt-[30vh]">
         <div className="flex-1 px-8 flex flex-col justify-end pb-12">
            <div className="mb-2 flex items-center gap-2 text-blue-400">
                <Navigation className="w-5 h-5 animate-pulse" />
                <span className="text-sm tracking-widest uppercase font-semibold">Rastreando Ubicación</span>
            </div>

            <div className="text-7xl font-mono font-bold tracking-tighter mb-2">
                {currentDistance !== null ? formatDistance(currentDistance) : '...'}
            </div>
            <p className="text-gray-400 text-lg mb-8">
                hacia {alarmConfig?.target.name}
            </p>

            <div className="h-32 w-full mb-8">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={distanceHistory}>
                        <YAxis domain={['auto', 'auto']} hide />
                        <Line 
                            type="monotone" 
                            dataKey="distance" 
                            stroke="#3b82f6" 
                            strokeWidth={3} 
                            dot={false}
                            isAnimationActive={false}
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancelar Alarma
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">¡DESPIERTA!</h1>
      <p className="text-xl opacity-90 text-center mb-12">Has llegado a {alarmConfig?.target.name}</p>

      <button 
          onClick={stopTracking}
          className="w-full max-w-sm bg-white text-red-600 py-6 rounded-3xl text-2xl font-bold shadow-xl active:scale-95 transition-transform"
      >
          ¡Estoy despierto!
      </button>
    </div>
  );

  return (
    <div className="min-h-screen bg-white font-sans antialiased">
      {status === AppStatus.IDLE && renderIdle()}
      {status === AppStatus.SEARCHING && renderSearching()}
      {status === AppStatus.CONFIRMING && renderConfirming()}
      {status === AppStatus.TRACKING && renderTracking()}
      {status === AppStatus.ALARM_TRIGGERED && renderAlarm()}
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Circle, useMap, Popup } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates, LocationInfo } from '../types';

// Fix for default Leaflet markers in React
const iconUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png";
const iconRetinaUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png";
const shadowUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png";

const DefaultIcon = L.icon({
  iconUrl,
  iconRetinaUrl,
  shadowUrl,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  tooltipAnchor: [16, -28],
  shadowSize: [41, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

interface MapDisplayProps {
  currentLocation?: Coordinates | null;
  targetLocation?: LocationInfo | null;
  radius?: number;
  center?: Coordinates;
  zoom?: number;
}

const MapUpdater: React.FC<{ center: Coordinates }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo([center.lat, center.lng], map.getZoom());
  }, [center, map]);
  return null;
};

const MapDisplay: React.FC<MapDisplayProps> = ({ 
  currentLocation, 
  targetLocation, 
  radius = 500, 
  center: explicitCenter, 
  zoom = 13 
}) => {
  // Priority: Explicit center -> Current Location -> Target Location -> Default (Montevideo/London)
  const center = explicitCenter || currentLocation || targetLocation || { lat: -34.9011, lng: -56.1645 };

  return (
    <MapContainer 
      center={[center.lat, center.lng]} 
      zoom={zoom} 
      scrollWheelZoom={true}
      className="h-full w-full rounded-xl z-0"
      zoomControl={false} // Cleaner for background
    >
      <TileLayer
        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
      />

      {targetLocation && (
        <>
          <Marker position={[targetLocation.lat, targetLocation.lng]}>
             <Popup>{targetLocation.name}</Popup>
          </Marker>
          <Circle 
            center={[targetLocation.lat, targetLocation.lng]} 
            pathOptions={{ fillColor: 'red', color: 'red' }} 
            radius={radius} 
          />
        </>
      )}

      {currentLocation && (
        <>
          <Marker 
            position={[currentLocation.lat, currentLocation.lng]}
            icon={L.divIcon({
              className: 'bg-blue-500 rounded-full border-2 border-white shadow-lg',
              iconSize: [16, 16],
              iconAnchor: [8, 8]
            })}
          />
          <MapUpdater center={currentLocation} />
        </>
      )}
    </MapContainer>
  );
};

export default MapDisplay;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapPin, Navigation, Bell, Search, StopCircle, Volume2, AlertCircle, RefreshCw, Loader2, ArrowLeft, X } from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
import { findLocation, generateAlarmAudio, getPlaceSuggestions } from './services/gemini';
import { calculateDistance, formatDistance } from './utils/geo';
import { AppStatus, LocationInfo, AlarmConfig, Coordinates } from './types';
import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [useHighAccuracy, setUseHighAccuracy] = useState(true); // New state for fallback logic

  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const debounceRef = useRef<number | null>(null);

  // Initialize Audio Context on user interaction
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }

      console.log(`Iniciando observador de geolocalización. Alta Precisión: ${useHighAccuracy}`);

      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          console.log("Ubicación actualizada:", newLocation);
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          console.warn(`Error de Geolocalización (Código ${error.code}):`, error.message);

          // FALLBACK LOGIC: If high accuracy times out, try low accuracy
          if (error.code === 3 /* TIMEOUT */ && useHighAccuracy) {
             console.log("Tiempo de espera agotado en alta precisión. Cambiando a baja precisión.");
             setLocationError("Señal GPS débil. Cambiando a ubicación por red...");
             setUseHighAccuracy(false); // This triggers re-effect with enableHighAccuracy: false
             return;
          }

          let msg = "No se puede acceder a la ubicación.";
          switch (error.code) {
            case 1: // PERMISSION_DENIED
              msg = "Permiso de ubicación denegado. Actívalo en la configuración de tu navegador.";
              break;
            case 2: // POSITION_UNAVAILABLE
              msg = "Ubicación no disponible. Verifica tu señal GPS.";
              break;
            case 3: // TIMEOUT
              msg = "Tiempo de espera agotado. Muévete a un área abierta.";
              break;
            default:
              msg = `Error de ubicación: ${error.message}`;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: useHighAccuracy, 
          maximumAge: 10000, 
          timeout: 30000 // 30s timeout
        }
      );
    } else {
      setLocationError("Tu navegador no soporta geolocalización.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [useHighAccuracy]);

  // Autocomplete Debounce Logic
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (query.trim().length > 2 && status === AppStatus.IDLE) {
      setIsSuggesting(true);
      debounceRef.current = window.setTimeout(async () => {
        try {
          const results = await getPlaceSuggestions(query, currentLocation);
          setSuggestions(results);
          setShowSuggestions(true);
        } catch (e) {
          console.error("Falló el autocompletado", e);
        } finally {
          setIsSuggesting(false);
        }
      }, 500); // 500ms debounce
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsSuggesting(false);
    }

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [query, currentLocation, status]);

  // Distance Tracking Logic
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20); // Keep last 20 points
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
  }, [currentLocation, status, alarmConfig]);

  // Wake Lock for mobile
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {
      console.log('Error Wake Lock:', err);
    }
  };

  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.log('Error al liberar Wake Lock', err);
      }
    }
  }, []);

  const executeSearch = async (searchQuery: string) => {
    if (!searchQuery.trim()) return;

    setStatus(AppStatus.SEARCHING);
    setShowSuggestions(false); // Hide autocomplete
    try {
      const location = await findLocation(searchQuery);

      const audioBase64 = await generateAlarmAudio(location.name);

      setAlarmConfig({
        target: location,
        radius: 500, 
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("No pudimos encontrar ese lugar. Inténtalo de nuevo.");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(query);
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    executeSearch(suggestion);
  };

  const startTracking = async () => {
    initAudio();
    await requestWakeLock();
    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    setQuery(''); // Clear query on reset
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;

    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }

      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);

      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) {
               // loop handles repetition
            }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };

      play();
    } catch (e) {
      console.error("Fallo en reproducción de audio", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden">
      {/* Background Map: Montevideo coordinates */}
      <div className="absolute inset-0 z-0 opacity-25 blur-[2px] pointer-events-none grayscale brightness-110">
        <MapDisplay 
          center={{ lat: -34.9011, lng: -56.1645 }} 
          zoom={13} 
        />
        {/* White overlay gradient to ensure text readability */}
        <div className="absolute inset-0 bg-gradient-to-b from-white/60 via-white/40 to-white/60"></div>
      </div>

      <div className="relative z-10 flex flex-col items-center w-full px-6">
        <div className="bg-blue-100 p-4 rounded-full mb-6 shadow-sm">
          <MapPin className="w-12 h-12 text-blue-600" />
        </div>
        <h1 className="text-4xl font-black text-gray-900 mb-2 tracking-tight">NapNav</h1>
        <p className="text-gray-700 font-medium text-center mb-10 max-w-xs drop-shadow-sm">
          Duerme en tu viaje. Te despertaremos cuando estés cerca.
        </p>

        <div className="w-full max-w-md relative group">
          <form onSubmit={handleSearch} className="w-full relative z-20">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
              placeholder="¿A dónde vas?"
              className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-gray-200/80 bg-white/90 backdrop-blur-sm focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-lg"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />

            {isSuggesting ? (
              <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 animate-spin" />
            ) : (
              <button 
                  type="submit" 
                  disabled={!query}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl font-medium disabled:opacity-50 hover:bg-blue-700 transition-colors shadow-md"
              >
                  Ir
              </button>
            )}
          </form>

          {/* Autocomplete Dropdown */}
          {showSuggestions && suggestions.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white/95 backdrop-blur-md rounded-xl shadow-xl border border-gray-100 overflow-hidden z-30 animate-in fade-in slide-in-from-top-2 duration-200">
              <ul className="divide-y divide-gray-50">
                {suggestions.map((item, idx) => (
                  <li key={idx}>
                    <button
                      onClick={() => handleSuggestionClick(item)}
                      className="w-full text-left px-5 py-3 hover:bg-blue-50 transition-colors flex items-center gap-3 text-gray-700 hover:text-blue-700"
                    >
                      <MapPin className="w-4 h-4 text-gray-400 shrink-0" />
                      <span className="truncate">{item}</span>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {locationError && (
          <div className="mt-8 flex flex-col items-center gap-2 max-w-sm text-center bg-white/80 backdrop-blur-sm p-4 rounded-2xl shadow-sm border border-gray-100">
              <div className="flex items-center gap-2 text-red-500">
                  <AlertCircle className="w-5 h-5 shrink-0" />
                  <span className="text-sm font-medium">{locationError}</span>
              </div>
              {locationError.includes("Permiso") && (
                  <p className="text-xs text-gray-400">
                      Revisa la configuración de tu navegador para permitir el acceso.
                  </p>
              )}
              {/* Manual retry button */}
              <button 
                onClick={() => { setLocationError(null); setUseHighAccuracy(true); window.location.reload(); }}
                className="text-blue-600 text-sm font-medium hover:underline flex items-center gap-1 mt-1"
              >
                <RefreshCw className="w-3 h-3" /> Reintentar GPS
              </button>
          </div>
        )}
      </div>
    </div>
  );

  const renderSearching = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] relative">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
      <p className="text-gray-600 font-medium text-center px-4">Consultando a Gemini para localizar el destino...</p>

      <button 
        onClick={() => setStatus(AppStatus.IDLE)}
        className="mt-8 flex items-center gap-2 text-gray-500 hover:text-gray-800 bg-gray-100 px-4 py-2 rounded-full transition-colors"
      >
        <X className="w-4 h-4" /> Cancelar
      </button>
    </div>
  );

  const renderConfirming = () => (
    <div className="flex flex-col h-screen bg-gray-50">
      <div className="h-1/2 w-full relative">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        <button 
            onClick={() => setStatus(AppStatus.IDLE)}
            className="absolute top-4 left-4 bg-white/95 p-3 rounded-full shadow-lg z-[400] hover:bg-gray-100 transition-colors"
            aria-label="Volver atrás"
        >
            <ArrowLeft className="w-6 h-6 text-gray-800" />
        </button>
      </div>

      <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
        <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

        <h2 className="text-2xl font-bold text-gray-900 mb-1">{alarmConfig?.target.name}</h2>
        <p className="text-gray-500 text-sm mb-6">{alarmConfig?.target.address}</p>

        <div className="bg-blue-50 p-4 rounded-2xl mb-6">
            <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-blue-800">Radio de Alarma</span>
                <span className="text-sm font-bold text-blue-900">{formatDistance(alarmConfig?.radius || 500)}</span>
            </div>
            <input 
                type="range" 
                min="100" 
                max="2000" 
                step="100"
                value={alarmConfig?.radius}
                onChange={(e) => setAlarmConfig(prev => prev ? ({...prev, radius: Number(e.target.value)}) : null)}
                className="w-full h-2 bg-blue-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
            <p className="text-xs text-blue-400 mt-2 text-center">Te avisaremos cuando estés a esta distancia.</p>
        </div>

        <div className="flex gap-3">
             <button 
                onClick={() => setStatus(AppStatus.IDLE)}
                className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-2xl text-lg font-bold hover:bg-gray-200 transition-colors"
            >
                Cancelar
            </button>
            <button 
                onClick={startTracking}
                className="flex-[2] bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
            >
                <Bell className="w-6 h-6" />
                Iniciar
            </button>
        </div>
      </div>
    </div>
  );

  const renderTracking = () => (
    <div className="flex flex-col h-screen bg-black text-white relative">
      <div className="absolute top-0 left-0 w-full h-1/2 opacity-50">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        {/* Overlay to dim map for focus */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black pointer-events-none z-[401]" />
      </div>

      <div className="relative z-10 flex flex-col h-full mt-[30vh]">
         <div className="flex-1 px-8 flex flex-col justify-end pb-12">
            <div className="mb-2 flex items-center gap-2 text-blue-400">
                <Navigation className="w-5 h-5 animate-pulse" />
                <span className="text-sm tracking-widest uppercase font-semibold">Rastreando Ubicación</span>
            </div>

            <div className="text-7xl font-mono font-bold tracking-tighter mb-2">
                {currentDistance !== null ? formatDistance(currentDistance) : '...'}
            </div>
            <p className="text-gray-400 text-lg mb-8">
                hacia {alarmConfig?.target.name}
            </p>

            <div className="h-32 w-full mb-8">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={distanceHistory}>
                        <YAxis domain={['auto', 'auto']} hide />
                        <Line 
                            type="monotone" 
                            dataKey="distance" 
                            stroke="#3b82f6" 
                            strokeWidth={3} 
                            dot={false}
                            isAnimationActive={false}
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancelar Alarma
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">¡DESPIERTA!</h1>
      <p className="text-xl opacity-90 text-center mb-12">Has llegado a {alarmConfig?.target.name}</p>

      <button 
          onClick={stopTracking}
          className="w-full max-w-sm bg-white text-red-600 py-6 rounded-3xl text-2xl font-bold shadow-xl active:scale-95 transition-transform"
      >
          ¡Estoy despierto!
      </button>
    </div>
  );

  return (
    <div className="min-h-screen bg-white font-sans antialiased">
      {status === AppStatus.IDLE && renderIdle()}
      {status === AppStatus.SEARCHING && renderSearching()}
      {status === AppStatus.CONFIRMING && renderConfirming()}
      {status === AppStatus.TRACKING && renderTracking()}
      {status === AppStatus.ALARM_TRIGGERED && renderAlarm()}
    </div>
  );
};

export default App;

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface LocationInfo extends Coordinates {
  name: string;
  address?: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  SEARCHING = 'SEARCHING',
  CONFIRMING = 'CONFIRMING',
  TRACKING = 'TRACKING',
  ALARM_TRIGGERED = 'ALARM_TRIGGERED',
  PROFILE = 'PROFILE',
}

export interface AlarmConfig {
  target: LocationInfo;
  radius: number; // in meters
  audioBase64: string | null;
}

export interface SavedPlace extends LocationInfo {
  id: string;
  defaultRadius?: number;
  dateAdded: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  MapPin, Navigation, Bell, Search, StopCircle, Volume2, 
  AlertCircle, RefreshCw, Loader2, ArrowLeft, X, User, 
  Settings, Heart, Trash2, History, ChevronRight 
} from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
import { findLocation, generateAlarmAudio, getPlaceSuggestions } from './services/gemini';
import { calculateDistance, formatDistance } from './utils/geo';
import { AppStatus, LocationInfo, AlarmConfig, Coordinates, SavedPlace } from './types';
import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [useHighAccuracy, setUseHighAccuracy] = useState(true); // Preference

  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Persistence State
  const [savedPlaces, setSavedPlaces] = useState<SavedPlace[]>([]);
  const [history, setHistory] = useState<SavedPlace[]>([]);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const debounceRef = useRef<number | null>(null);

  // Load from LocalStorage
  useEffect(() => {
    const loadedPlaces = localStorage.getItem('napnav_places');
    const loadedHistory = localStorage.getItem('napnav_history');
    if (loadedPlaces) setSavedPlaces(JSON.parse(loadedPlaces));
    if (loadedHistory) setHistory(JSON.parse(loadedHistory));
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem('napnav_places', JSON.stringify(savedPlaces));
  }, [savedPlaces]);

  useEffect(() => {
    localStorage.setItem('napnav_history', JSON.stringify(history));
  }, [history]);

  // Initialize Audio Context
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }

      console.log(`Iniciando observador de geolocalización. Alta Precisión: ${useHighAccuracy}`);

      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          // Fallback logic handled here only if actively tracking or showing map
          if (error.code === 3 && useHighAccuracy) {
             console.log("Timeout alta precisión -> Fallback.");
             // Optional: setUseHighAccuracy(false) automatic fallback
          }
          let msg = "Ubicación no disponible.";
           switch (error.code) {
            case 1: msg = "Permiso denegado."; break;
            case 2: msg = "Sin señal GPS."; break;
            case 3: msg = "Tiempo agotado."; break;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: useHighAccuracy, 
          maximumAge: 10000, 
          timeout: 30000 
        }
      );
    } else {
      setLocationError("Navegador no soportado.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [useHighAccuracy]);

  // Autocomplete
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (query.trim().length > 2 && status === AppStatus.IDLE) {
      setIsSuggesting(true);
      debounceRef.current = window.setTimeout(async () => {
        try {
          const results = await getPlaceSuggestions(query, currentLocation);
          setSuggestions(results);
          setShowSuggestions(true);
        } catch (e) {
          console.error("Falló el autocompletado", e);
        } finally {
          setIsSuggesting(false);
        }
      }, 500); 
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsSuggesting(false);
    }

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [query, currentLocation, status]);

  // Distance Tracking
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20);
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
  }, [currentLocation, status, alarmConfig]);

  // Wake Lock
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {
      console.log('Error Wake Lock:', err);
    }
  };

  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.log('Error al liberar Wake Lock', err);
      }
    }
  }, []);

  // --- Logic Functions ---

  const executeSearch = async (searchQuery: string, radiusOverride?: number) => {
    if (!searchQuery.trim()) return;

    setStatus(AppStatus.SEARCHING);
    setShowSuggestions(false);
    try {
      const location = await findLocation(searchQuery);
      const audioBase64 = await generateAlarmAudio(location.name);

      setAlarmConfig({
        target: location,
        radius: radiusOverride || 500, 
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("No pudimos encontrar ese lugar. Inténtalo de nuevo.");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(query);
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    executeSearch(suggestion);
  };

  const startTracking = async () => {
    if (!alarmConfig) return;
    initAudio();
    await requestWakeLock();

    // Add to history
    const newHistoryItem: SavedPlace = {
      ...alarmConfig.target,
      id: Date.now().toString(),
      dateAdded: Date.now(),
      defaultRadius: alarmConfig.radius
    };
    // Keep last 10 items, remove duplicates by name
    setHistory(prev => {
      const filtered = prev.filter(p => p.name !== newHistoryItem.name);
      return [newHistoryItem, ...filtered].slice(0, 10);
    });

    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    setQuery(''); 
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;
    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);
      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) { /* loop */ }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };
      play();
    } catch (e) {
      console.error("Fallo en reproducción de audio", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  const toggleSavedPlace = (place: LocationInfo) => {
    const exists = savedPlaces.find(p => p.name === place.name && p.lat === place.lat);
    if (exists) {
      setSavedPlaces(prev => prev.filter(p => p.id !== exists.id));
    } else {
      const newPlace: SavedPlace = {
        ...place,
        id: Date.now().toString(),
        dateAdded: Date.now()
      };
      setSavedPlaces(prev => [newPlace, ...prev]);
    }
  };

  const isSaved = (place: LocationInfo | undefined) => {
    if (!place) return false;
    return savedPlaces.some(p => p.name === place.name && p.lat === place.lat);
  };

  const deleteSavedPlace = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSavedPlaces(prev => prev.filter(p => p.id !== id));
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0 z-0 opacity-25 blur-[2px] pointer-events-none grayscale brightness-110">
        <MapDisplay center={{ lat: -34.9011, lng: -56.1645 }} zoom={13} />
        <div className="absolute inset-0 bg-gradient-to-b from-white/60 via-white/40 to-white/60"></div>
      </div>

      {/* Top Bar */}
      <div className="absolute top-0 left-0 right-0 p-6 flex justify-end z-20">
        <button 
          onClick={() => setStatus(AppStatus.PROFILE)}
          className="bg-white/80 backdrop-blur-md p-3 rounded-full shadow-sm hover:bg-white transition-all text-gray-700"
        >
          <User className="w-6 h-6" />
        </button>
      </div>

      <div className="relative z-10 flex flex-col items-center w-full px-6">
        <div className="bg-blue-100 p-4 rounded-full mb-6 shadow-sm">
          <MapPin className="w-12 h-12 text-blue-600" />
        </div>
        <h1 className="text-4xl font-black text-gray-900 mb-2 tracking-tight">NapNav</h1>
        <p className="text-gray-700 font-medium text-center mb-10 max-w-xs drop-shadow-sm">
          Duerme en tu viaje. Te despertaremos cuando estés cerca.
        </p>

        <div className="w-full max-w-md relative group">
          <form onSubmit={handleSearch} className="w-full relative z-20">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
              placeholder="¿A dónde vas?"
              className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-gray-200/80 bg-white/90 backdrop-blur-sm focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-lg"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />

            {isSuggesting ? (
              <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 animate-spin" />
            ) : (
              <button 
                  type="submit" 
                  disabled={!query}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl font-medium disabled:opacity-50 hover:bg-blue-700 transition-colors shadow-md"
              >
                  Ir
              </button>
            )}
          </form>

          {/* Autocomplete */}
          {showSuggestions && suggestions.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white/95 backdrop-blur-md rounded-xl shadow-xl border border-gray-100 overflow-hidden z-30 animate-in fade-in slide-in-from-top-2 duration-200">
              <ul className="divide-y divide-gray-50">
                {suggestions.map((item, idx) => (
                  <li key={idx}>
                    <button
                      onClick={() => handleSuggestionClick(item)}
                      className="w-full text-left px-5 py-3 hover:bg-blue-50 transition-colors flex items-center gap-3 text-gray-700 hover:text-blue-700"
                    >
                      <MapPin className="w-4 h-4 text-gray-400 shrink-0" />
                      <span className="truncate">{item}</span>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {locationError && (
          <div className="mt-8 flex flex-col items-center gap-2 max-w-sm text-center bg-white/80 backdrop-blur-sm p-4 rounded-2xl shadow-sm border border-gray-100">
              <div className="flex items-center gap-2 text-red-500">
                  <AlertCircle className="w-5 h-5 shrink-0" />
                  <span className="text-sm font-medium">{locationError}</span>
              </div>
              <button 
                onClick={() => { setLocationError(null); setUseHighAccuracy(true); window.location.reload(); }}
                className="text-blue-600 text-sm font-medium hover:underline flex items-center gap-1 mt-1"
              >
                <RefreshCw className="w-3 h-3" /> Reintentar GPS
              </button>
          </div>
        )}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <div className="bg-white p-6 pb-8 border-b border-gray-200">
        <button 
          onClick={() => setStatus(AppStatus.IDLE)} 
          className="mb-6 p-2 -ml-2 rounded-full hover:bg-gray-100 inline-flex transition-colors"
        >
          <ArrowLeft className="w-6 h-6 text-gray-700" />
        </button>
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center border-2 border-white shadow-sm">
            <User className="w-8 h-8 text-blue-600" />
          </div>
          <div>
            <h2 className="text-2xl font-bold text-gray-900">Mi Perfil</h2>
            <p className="text-gray-500 text-sm">Gestiona tus rutas y preferencias</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">

        {/* Section: Preferences */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <Settings className="w-4 h-4" /> Preferencias
          </h3>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-4 flex items-center justify-between">
              <div>
                <p className="font-medium text-gray-900">GPS de Alta Precisión</p>
                <p className="text-xs text-gray-500">Consume más batería pero es más exacto.</p>
              </div>
              <button 
                onClick={() => setUseHighAccuracy(!useHighAccuracy)}
                className={`w-12 h-6 rounded-full transition-colors relative ${useHighAccuracy ? 'bg-blue-600' : 'bg-gray-200'}`}
              >
                <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-transform ${useHighAccuracy ? 'left-7' : 'left-1'}`} />
              </button>
            </div>
          </div>
        </section>

        {/* Section: Locations */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <Heart className="w-4 h-4" /> Mis Lugares
          </h3>
          {savedPlaces.length === 0 ? (
            <div className="text-center py-8 bg-white rounded-xl border border-dashed border-gray-200">
              <p className="text-gray-400 text-sm">No tienes lugares guardados.</p>
            </div>
          ) : (
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden divide-y divide-gray-50">
              {savedPlaces.map(place => (
                <div key={place.id} className="p-4 flex items-center justify-between group hover:bg-gray-50 transition-colors">
                  <div 
                    onClick={() => {
                        setQuery(place.name);
                        executeSearch(place.name, place.defaultRadius);
                    }}
                    className="flex-1 cursor-pointer"
                  >
                    <p className="font-medium text-gray-900">{place.name}</p>
                    <p className="text-xs text-gray-500 truncate">{place.address || "Coordenadas guardadas"}</p>
                  </div>
                  <button 
                    onClick={(e) => deleteSavedPlace(place.id, e)}
                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Section: History */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <History className="w-4 h-4" /> Historial de Alarmas
          </h3>
          {history.length === 0 ? (
            <div className="text-center py-8 bg-white rounded-xl border border-dashed border-gray-200">
              <p className="text-gray-400 text-sm">Tus viajes recientes aparecerán aquí.</p>
            </div>
          ) : (
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden divide-y divide-gray-50">
              {history.map(item => (
                <div 
                    key={item.id} 
                    onClick={() => {
                        setQuery(item.name);
                        executeSearch(item.name, item.defaultRadius);
                    }}
                    className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-50 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center text-blue-600">
                        <Bell className="w-4 h-4" />
                    </div>
                    <div>
                        <p className="font-medium text-gray-900">{item.name}</p>
                        <p className="text-xs text-gray-500">Radio: {formatDistance(item.defaultRadius || 500)}</p>
                    </div>
                  </div>
                  <ChevronRight className="w-4 h-4 text-gray-300" />
                </div>
              ))}
            </div>
          )}
        </section>

      </div>
    </div>
  );

  const renderSearching = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] relative">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
      <p className="text-gray-600 font-medium text-center px-4">Consultando a Gemini para localizar el destino...</p>

      <button 
        onClick={() => setStatus(AppStatus.IDLE)}
        className="mt-8 flex items-center gap-2 text-gray-500 hover:text-gray-800 bg-gray-100 px-4 py-2 rounded-full transition-colors"
      >
        <X className="w-4 h-4" /> Cancelar
      </button>
    </div>
  );

  const renderConfirming = () => {
    const isFavorite = isSaved(alarmConfig?.target);

    return (
      <div className="flex flex-col h-screen bg-gray-50">
        <div className="h-1/2 w-full relative">
          <MapDisplay 
              currentLocation={currentLocation} 
              targetLocation={alarmConfig?.target || null}
              radius={alarmConfig?.radius || 500}
          />
          <button 
              onClick={() => setStatus(AppStatus.IDLE)}
              className="absolute top-4 left-4 bg-white/95 p-3 rounded-full shadow-lg z-[400] hover:bg-gray-100 transition-colors"
              aria-label="Volver atrás"
          >
              <ArrowLeft className="w-6 h-6 text-gray-800" />
          </button>
        </div>

        <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
          <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

          <div className="flex justify-between items-start mb-1">
             <h2 className="text-2xl font-bold text-gray-900 flex-1 mr-2">{alarmConfig?.target.name}</h2>
             <button 
                onClick={() => alarmConfig && toggleSavedPlace(alarmConfig.target)}
                className={`p-2 rounded-full transition-colors ${isFavorite ? 'bg-red-50 text-red-500' : 'bg-gray-100 text-gray-400'}`}
             >
                <Heart className={`w-6 h-6 ${isFavorite ? 'fill-current' : ''}`} />
             </button>
          </div>

          <p className="text-gray-500 text-sm mb-6">{alarmConfig?.target.address}</p>

          <div className="bg-blue-50 p-4 rounded-2xl mb-6">
              <div className="flex justify-between items-center mb-2">
                  <span className="text-sm font-medium text-blue-800">Radio de Alarma</span>
                  <span className="text-sm font-bold text-blue-900">{formatDistance(alarmConfig?.radius || 500)}</span>
              </div>
              <input 
                  type="range" 
                  min="100" 
                  max="2000" 
                  step="100"
                  value={alarmConfig?.radius}
                  onChange={(e) => setAlarmConfig(prev => prev ? ({...prev, radius: Number(e.target.value)}) : null)}
                  className="w-full h-2 bg-blue-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
              <p className="text-xs text-blue-400 mt-2 text-center">Te avisaremos cuando estés a esta distancia.</p>
          </div>

          <div className="flex gap-3">
               <button 
                  onClick={() => setStatus(AppStatus.IDLE)}
                  className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-2xl text-lg font-bold hover:bg-gray-200 transition-colors"
              >
                  Cancelar
              </button>
              <button 
                  onClick={startTracking}
                  className="flex-[2] bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                  <Bell className="w-6 h-6" />
                  Iniciar
              </button>
          </div>
        </div>
      </div>
    );
  };

  const renderTracking = () => (
    <div className="flex flex-col h-screen bg-black text-white relative">
      <div className="absolute top-0 left-0 w-full h-1/2 opacity-50">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black pointer-events-none z-[401]" />
      </div>

      <div className="relative z-10 flex flex-col h-full mt-[30vh]">
         <div className="flex-1 px-8 flex flex-col justify-end pb-12">
            <div className="mb-2 flex items-center gap-2 text-blue-400">
                <Navigation className="w-5 h-5 animate-pulse" />
                <span className="text-sm tracking-widest uppercase font-semibold">Rastreando Ubicación</span>
            </div>

            <div className="text-7xl font-mono font-bold tracking-tighter mb-2">
                {currentDistance !== null ? formatDistance(currentDistance) : '...'}
            </div>
            <p className="text-gray-400 text-lg mb-8">
                hacia {alarmConfig?.target.name}
            </p>

            <div className="h-32 w-full mb-8">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={distanceHistory}>
                        <YAxis domain={['auto', 'auto']} hide />
                        <Line 
                            type="monotone" 
                            dataKey="distance" 
                            stroke="#3b82f6" 
                            strokeWidth={3} 
                            dot={false}
                            isAnimationActive={false}
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancelar Alarma
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">¡DESPIERTA!</h1>
      <p className="text-xl opacity-90 text-center mb-12">Has llegado a {alarmConfig?.target.name}</p>

      <button 
          onClick={stopTracking}
          className="w-full max-w-sm bg-white text-red-600 py-6 rounded-3xl text-2xl font-bold shadow-xl active:scale-95 transition-transform"
      >
          ¡Estoy despierto!
      </button>
    </div>
  );

  return (
    <div className="min-h-screen bg-white font-sans antialiased">
      {status === AppStatus.IDLE && renderIdle()}
      {status === AppStatus.PROFILE && renderProfile()}
      {status === AppStatus.SEARCHING && renderSearching()}
      {status === AppStatus.CONFIRMING && renderConfirming()}
      {status === AppStatus.TRACKING && renderTracking()}
      {status === AppStatus.ALARM_TRIGGERED && renderAlarm()}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  MapPin, Navigation, Bell, Search, StopCircle, Volume2, 
  AlertCircle, RefreshCw, Loader2, ArrowLeft, X, User, 
  Settings, Heart, Trash2, History, ChevronRight 
} from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
import { findLocation, generateAlarmAudio, getPlaceSuggestions } from './services/gemini';
import { calculateDistance, formatDistance } from './utils/geo';
import { AppStatus, LocationInfo, AlarmConfig, Coordinates, SavedPlace } from './types';
import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [useHighAccuracy, setUseHighAccuracy] = useState(true); // Preference

  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Persistence State
  const [savedPlaces, setSavedPlaces] = useState<SavedPlace[]>([]);
  const [history, setHistory] = useState<SavedPlace[]>([]);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const debounceRef = useRef<number | null>(null);

  // Load from LocalStorage
  useEffect(() => {
    const loadedPlaces = localStorage.getItem('napnav_places');
    const loadedHistory = localStorage.getItem('napnav_history');
    if (loadedPlaces) setSavedPlaces(JSON.parse(loadedPlaces));
    if (loadedHistory) setHistory(JSON.parse(loadedHistory));
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem('napnav_places', JSON.stringify(savedPlaces));
  }, [savedPlaces]);

  useEffect(() => {
    localStorage.setItem('napnav_history', JSON.stringify(history));
  }, [history]);

  // Initialize Audio Context
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }

      console.log(`Iniciando observador de geolocalización. Alta Precisión: ${useHighAccuracy}`);

      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          // Fallback logic handled here only if actively tracking or showing map
          if (error.code === 3 && useHighAccuracy) {
             console.log("Timeout alta precisión -> Fallback.");
             // Optional: setUseHighAccuracy(false) automatic fallback
          }
          let msg = "Ubicación no disponible.";
           switch (error.code) {
            case 1: msg = "Permiso denegado."; break;
            case 2: msg = "Sin señal GPS."; break;
            case 3: msg = "Tiempo agotado."; break;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: useHighAccuracy, 
          maximumAge: 10000, 
          timeout: 30000 
        }
      );
    } else {
      setLocationError("Navegador no soportado.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [useHighAccuracy]);

  // Autocomplete
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (query.trim().length > 2 && status === AppStatus.IDLE) {
      setIsSuggesting(true);
      debounceRef.current = window.setTimeout(async () => {
        try {
          const results = await getPlaceSuggestions(query, currentLocation);
          setSuggestions(results);
          setShowSuggestions(true);
        } catch (e) {
          console.error("Falló el autocompletado", e);
        } finally {
          setIsSuggesting(false);
        }
      }, 500); 
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsSuggesting(false);
    }

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [query, currentLocation, status]);

  // Distance Tracking
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20);
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
  }, [currentLocation, status, alarmConfig]);

  // Wake Lock
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {
      console.log('Error Wake Lock:', err);
    }
  };

  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.log('Error al liberar Wake Lock', err);
      }
    }
  }, []);

  // --- Logic Functions ---

  const executeSearch = async (searchQuery: string, radiusOverride?: number) => {
    if (!searchQuery.trim()) return;

    setStatus(AppStatus.SEARCHING);
    setShowSuggestions(false);
    try {
      const location = await findLocation(searchQuery);
      const audioBase64 = await generateAlarmAudio(location.name);

      setAlarmConfig({
        target: location,
        radius: radiusOverride || 500, 
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("No pudimos encontrar ese lugar. Inténtalo de nuevo.");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(query);
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    executeSearch(suggestion);
  };

  const startTracking = async () => {
    if (!alarmConfig) return;
    initAudio();
    await requestWakeLock();

    // Add to history
    const newHistoryItem: SavedPlace = {
      ...alarmConfig.target,
      id: Date.now().toString(),
      dateAdded: Date.now(),
      defaultRadius: alarmConfig.radius
    };
    // Keep last 10 items, remove duplicates by name
    setHistory(prev => {
      const filtered = prev.filter(p => p.name !== newHistoryItem.name);
      return [newHistoryItem, ...filtered].slice(0, 10);
    });

    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    setQuery(''); 
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;
    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);
      const play = () => {
        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current!.destination);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) { /* loop */ }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };
      play();
    } catch (e) {
      console.error("Fallo en reproducción de audio", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  const toggleSavedPlace = (place: LocationInfo) => {
    const exists = savedPlaces.find(p => p.name === place.name && p.lat === place.lat);
    if (exists) {
      setSavedPlaces(prev => prev.filter(p => p.id !== exists.id));
    } else {
      const newPlace: SavedPlace = {
        ...place,
        id: Date.now().toString(),
        dateAdded: Date.now()
      };
      setSavedPlaces(prev => [newPlace, ...prev]);
    }
  };

  const isSaved = (place: LocationInfo | undefined) => {
    if (!place) return false;
    return savedPlaces.some(p => p.name === place.name && p.lat === place.lat);
  };

  const deleteSavedPlace = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSavedPlaces(prev => prev.filter(p => p.id !== id));
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0 z-0 opacity-25 blur-[2px] pointer-events-none grayscale brightness-110">
        <MapDisplay center={{ lat: -34.9011, lng: -56.1645 }} zoom={13} />
        <div className="absolute inset-0 bg-gradient-to-b from-white/60 via-white/40 to-white/60"></div>
      </div>

      {/* Top Bar */}
      <div className="absolute top-0 left-0 right-0 p-6 flex justify-end z-20">
        <button 
          onClick={() => setStatus(AppStatus.PROFILE)}
          className="bg-white/80 backdrop-blur-md p-3 rounded-full shadow-sm hover:bg-white transition-all text-gray-700"
        >
          <User className="w-6 h-6" />
        </button>
      </div>

      <div className="relative z-10 flex flex-col items-center w-full px-6">
        <div className="bg-blue-100 p-4 rounded-full mb-6 shadow-sm">
          <MapPin className="w-12 h-12 text-blue-600" />
        </div>
        <h1 className="text-4xl font-black text-gray-900 mb-2 tracking-tight">NapNav</h1>
        <p className="text-gray-700 font-medium text-center mb-10 max-w-xs drop-shadow-sm">
          Duerme en tu viaje. Te despertaremos cuando estés cerca.
        </p>

        <div className="w-full max-w-md relative group">
          <form onSubmit={handleSearch} className="w-full relative z-20">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
              placeholder="¿A dónde vas?"
              className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-gray-200/80 bg-white/90 backdrop-blur-sm focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-lg text-gray-900 placeholder:text-gray-400"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />

            {isSuggesting ? (
              <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 animate-spin" />
            ) : (
              <button 
                  type="submit" 
                  disabled={!query}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl font-medium disabled:opacity-50 hover:bg-blue-700 transition-colors shadow-md"
              >
                  Ir
              </button>
            )}
          </form>

          {/* Autocomplete */}
          {showSuggestions && suggestions.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white/95 backdrop-blur-md rounded-xl shadow-xl border border-gray-100 overflow-hidden z-30 animate-in fade-in slide-in-from-top-2 duration-200">
              <ul className="divide-y divide-gray-50">
                {suggestions.map((item, idx) => (
                  <li key={idx}>
                    <button
                      onClick={() => handleSuggestionClick(item)}
                      className="w-full text-left px-5 py-3 hover:bg-blue-50 transition-colors flex items-center gap-3 text-gray-700 hover:text-blue-700"
                    >
                      <MapPin className="w-4 h-4 text-gray-400 shrink-0" />
                      <span className="truncate">{item}</span>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {locationError && (
          <div className="mt-8 flex flex-col items-center gap-2 max-w-sm text-center bg-white/80 backdrop-blur-sm p-4 rounded-2xl shadow-sm border border-gray-100">
              <div className="flex items-center gap-2 text-red-500">
                  <AlertCircle className="w-5 h-5 shrink-0" />
                  <span className="text-sm font-medium">{locationError}</span>
              </div>
              <button 
                onClick={() => { setLocationError(null); setUseHighAccuracy(true); window.location.reload(); }}
                className="text-blue-600 text-sm font-medium hover:underline flex items-center gap-1 mt-1"
              >
                <RefreshCw className="w-3 h-3" /> Reintentar GPS
              </button>
          </div>
        )}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <div className="bg-white p-6 pb-8 border-b border-gray-200">
        <button 
          onClick={() => setStatus(AppStatus.IDLE)} 
          className="mb-6 p-2 -ml-2 rounded-full hover:bg-gray-100 inline-flex transition-colors"
        >
          <ArrowLeft className="w-6 h-6 text-gray-700" />
        </button>
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center border-2 border-white shadow-sm">
            <User className="w-8 h-8 text-blue-600" />
          </div>
          <div>
            <h2 className="text-2xl font-bold text-gray-900">Mi Perfil</h2>
            <p className="text-gray-500 text-sm">Gestiona tus rutas y preferencias</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">

        {/* Section: Preferences */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <Settings className="w-4 h-4" /> Preferencias
          </h3>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-4 flex items-center justify-between">
              <div>
                <p className="font-medium text-gray-900">GPS de Alta Precisión</p>
                <p className="text-xs text-gray-500">Consume más batería pero es más exacto.</p>
              </div>
              <button 
                onClick={() => setUseHighAccuracy(!useHighAccuracy)}
                className={`w-12 h-6 rounded-full transition-colors relative ${useHighAccuracy ? 'bg-blue-600' : 'bg-gray-200'}`}
              >
                <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-transform ${useHighAccuracy ? 'left-7' : 'left-1'}`} />
              </button>
            </div>
          </div>
        </section>

        {/* Section: Locations */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <Heart className="w-4 h-4" /> Mis Lugares
          </h3>
          {savedPlaces.length === 0 ? (
            <div className="text-center py-8 bg-white rounded-xl border border-dashed border-gray-200">
              <p className="text-gray-400 text-sm">No tienes lugares guardados.</p>
            </div>
          ) : (
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden divide-y divide-gray-50">
              {savedPlaces.map(place => (
                <div key={place.id} className="p-4 flex items-center justify-between group hover:bg-gray-50 transition-colors">
                  <div 
                    onClick={() => {
                        setQuery(place.name);
                        executeSearch(place.name, place.defaultRadius);
                    }}
                    className="flex-1 cursor-pointer"
                  >
                    <p className="font-medium text-gray-900">{place.name}</p>
                    <p className="text-xs text-gray-500 truncate">{place.address || "Coordenadas guardadas"}</p>
                  </div>
                  <button 
                    onClick={(e) => deleteSavedPlace(place.id, e)}
                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Section: History */}
        <section>
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <History className="w-4 h-4" /> Historial de Alarmas
          </h3>
          {history.length === 0 ? (
            <div className="text-center py-8 bg-white rounded-xl border border-dashed border-gray-200">
              <p className="text-gray-400 text-sm">Tus viajes recientes aparecerán aquí.</p>
            </div>
          ) : (
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden divide-y divide-gray-50">
              {history.map(item => (
                <div 
                    key={item.id} 
                    onClick={() => {
                        setQuery(item.name);
                        executeSearch(item.name, item.defaultRadius);
                    }}
                    className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-50 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center text-blue-600">
                        <Bell className="w-4 h-4" />
                    </div>
                    <div>
                        <p className="font-medium text-gray-900">{item.name}</p>
                        <p className="text-xs text-gray-500">Radio: {formatDistance(item.defaultRadius || 500)}</p>
                    </div>
                  </div>
                  <ChevronRight className="w-4 h-4 text-gray-300" />
                </div>
              ))}
            </div>
          )}
        </section>

      </div>
    </div>
  );

  const renderSearching = () => (
    <div className="flex flex-col items-center justify-center min-h-[60vh] relative">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
      <p className="text-gray-600 font-medium text-center px-4">Consultando a Gemini para localizar el destino...</p>

      <button 
        onClick={() => setStatus(AppStatus.IDLE)}
        className="mt-8 flex items-center gap-2 text-gray-500 hover:text-gray-800 bg-gray-100 px-4 py-2 rounded-full transition-colors"
      >
        <X className="w-4 h-4" /> Cancelar
      </button>
    </div>
  );

  const renderConfirming = () => {
    const isFavorite = isSaved(alarmConfig?.target);

    return (
      <div className="flex flex-col h-screen bg-gray-50">
        <div className="h-1/2 w-full relative">
          <MapDisplay 
              currentLocation={currentLocation} 
              targetLocation={alarmConfig?.target || null}
              radius={alarmConfig?.radius || 500}
          />
          <button 
              onClick={() => setStatus(AppStatus.IDLE)}
              className="absolute top-4 left-4 bg-white/95 p-3 rounded-full shadow-lg z-[400] hover:bg-gray-100 transition-colors"
              aria-label="Volver atrás"
          >
              <ArrowLeft className="w-6 h-6 text-gray-800" />
          </button>
        </div>

        <div className="h-1/2 bg-white rounded-t-3xl -mt-6 relative z-10 px-6 py-8 flex flex-col shadow-[0_-4px_20px_rgba(0,0,0,0.1)]">
          <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6"></div>

          <div className="flex justify-between items-start mb-1">
             <h2 className="text-2xl font-bold text-gray-900 flex-1 mr-2">{alarmConfig?.target.name}</h2>
             <button 
                onClick={() => alarmConfig && toggleSavedPlace(alarmConfig.target)}
                className={`p-2 rounded-full transition-colors ${isFavorite ? 'bg-red-50 text-red-500' : 'bg-gray-100 text-gray-400'}`}
             >
                <Heart className={`w-6 h-6 ${isFavorite ? 'fill-current' : ''}`} />
             </button>
          </div>

          <p className="text-gray-500 text-sm mb-6">{alarmConfig?.target.address}</p>

          <div className="bg-blue-50 p-4 rounded-2xl mb-6">
              <div className="flex justify-between items-center mb-2">
                  <span className="text-sm font-medium text-blue-800">Radio de Alarma</span>
                  <span className="text-sm font-bold text-blue-900">{formatDistance(alarmConfig?.radius || 500)}</span>
              </div>
              <input 
                  type="range" 
                  min="100" 
                  max="2000" 
                  step="100"
                  value={alarmConfig?.radius}
                  onChange={(e) => setAlarmConfig(prev => prev ? ({...prev, radius: Number(e.target.value)}) : null)}
                  className="w-full h-2 bg-blue-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
              <p className="text-xs text-blue-400 mt-2 text-center">Te avisaremos cuando estés a esta distancia.</p>
          </div>

          <div className="flex gap-3">
               <button 
                  onClick={() => setStatus(AppStatus.IDLE)}
                  className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-2xl text-lg font-bold hover:bg-gray-200 transition-colors"
              >
                  Cancelar
              </button>
              <button 
                  onClick={startTracking}
                  className="flex-[2] bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                  <Bell className="w-6 h-6" />
                  Iniciar
              </button>
          </div>
        </div>
      </div>
    );
  };

  const renderTracking = () => (
    <div className="flex flex-col h-screen bg-black text-white relative">
      <div className="absolute top-0 left-0 w-full h-1/2 opacity-50">
        <MapDisplay 
            currentLocation={currentLocation} 
            targetLocation={alarmConfig?.target || null}
            radius={alarmConfig?.radius || 500}
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black pointer-events-none z-[401]" />
      </div>

      <div className="relative z-10 flex flex-col h-full mt-[30vh]">
         <div className="flex-1 px-8 flex flex-col justify-end pb-12">
            <div className="mb-2 flex items-center gap-2 text-blue-400">
                <Navigation className="w-5 h-5 animate-pulse" />
                <span className="text-sm tracking-widest uppercase font-semibold">Rastreando Ubicación</span>
            </div>

            <div className="text-7xl font-mono font-bold tracking-tighter mb-2">
                {currentDistance !== null ? formatDistance(currentDistance) : '...'}
            </div>
            <p className="text-gray-400 text-lg mb-8">
                hacia {alarmConfig?.target.name}
            </p>

            <div className="h-32 w-full mb-8">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={distanceHistory}>
                        <YAxis domain={['auto', 'auto']} hide />
                        <Line 
                            type="monotone" 
                            dataKey="distance" 
                            stroke="#3b82f6" 
                            strokeWidth={3} 
                            dot={false}
                            isAnimationActive={false}
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <button 
                onClick={stopTracking}
                className="w-full bg-gray-800 text-white py-4 rounded-2xl text-lg font-bold border border-gray-700 active:bg-gray-700 transition-colors flex items-center justify-center gap-2"
            >
                <StopCircle className="w-6 h-6" />
                Cancelar Alarma
            </button>
         </div>
      </div>
    </div>
  );

  const renderAlarm = () => (
    <div className="fixed inset-0 bg-red-600 text-white z-50 flex flex-col items-center justify-center p-8 animate-pulse">
      <Volume2 className="w-24 h-24 mb-8" />
      <h1 className="text-5xl font-black text-center mb-4 leading-tight">¡DESPIERTA!</h1>
      <p className="text-xl opacity-90 text-center mb-12">Has llegado a {alarmConfig?.target.name}</p>

      <button 
          onClick={stopTracking}
          className="w-full max-w-sm bg-white text-red-600 py-6 rounded-3xl text-2xl font-bold shadow-xl active:scale-95 transition-transform"
      >
          ¡Estoy despierto!
      </button>
    </div>
  );

  return (
    <div className="min-h-screen bg-white font-sans antialiased">
      {status === AppStatus.IDLE && renderIdle()}
      {status === AppStatus.PROFILE && renderProfile()}
      {status === AppStatus.SEARCHING && renderSearching()}
      {status === AppStatus.CONFIRMING && renderConfirming()}
      {status === AppStatus.TRACKING && renderTracking()}
      {status === AppStatus.ALARM_TRIGGERED && renderAlarm()}
    </div>
  );
};

export default App;

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface LocationInfo extends Coordinates {
  name: string;
  address?: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  SEARCHING = 'SEARCHING',
  CONFIRMING = 'CONFIRMING',
  TRACKING = 'TRACKING',
  ALARM_TRIGGERED = 'ALARM_TRIGGERED',
  PROFILE = 'PROFILE',
  SETTINGS = 'SETTINGS',
}

export type AlarmIntensity = 'soft' | 'normal' | 'intense';

export interface AlarmSettings {
  volume: number; // 0 to 100
  vibration: boolean;
  intensity: AlarmIntensity;
}

export interface AlarmConfig {
  target: LocationInfo;
  radius: number; // in meters
  audioBase64: string | null;
}

export interface SavedPlace extends LocationInfo {
  id: string;
  defaultRadius?: number;
  dateAdded: number;
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocationInfo, Coordinates, AlarmIntensity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findLocation = async (query: string): Promise<LocationInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the geographic coordinates (latitude and longitude) for: "${query}". Return the result in JSON format with lat, lng, name, and a short address. Ensure the address is in Spanish if possible.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER },
          lng: { type: Type.NUMBER },
          name: { type: Type.STRING },
          address: { type: Type.STRING },
        },
        required: ["lat", "lng", "name"],
      },
    },
  });

  if (!response.text) {
    throw new Error("No se pudo resolver la ubicación");
  }

  return JSON.parse(response.text) as LocationInfo;
};

export const getPlaceSuggestions = async (query: string, userLocation: Coordinates | null): Promise<string[]> => {
  const context = userLocation 
    ? `The user is currently at latitude ${userLocation.lat}, longitude ${userLocation.lng}. You MUST prioritize places geographically close to this location. Ignore places on other continents unless explicitly typed.` 
    : '';

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Autocomplete suggestions for location search in Spanish. User input: "${query}". ${context} Return a JSON array of 5 distinct place names or addresses that match. Keep them concise and relevant to the local context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });

  if (!response.text) return [];
  try {
    return JSON.parse(response.text) as string[];
  } catch (e) {
    return [];
  }
};

export const generateAlarmAudio = async (locationName: string, intensity: AlarmIntensity = 'normal'): Promise<string> => {
  let promptText = `¡Despierta! Estás llegando a ${locationName}. ¡No pierdas tu parada!`;
  let voiceName = 'Zephyr';

  switch (intensity) {
    case 'soft':
      promptText = `Disculpa, ya estamos cerca de ${locationName}. Es hora de prepararse para bajar.`;
      voiceName = 'Kore'; // Often softer
      break;
    case 'intense':
      promptText = `¡ATENCIÓN! ¡LLEGANDO A ${locationName}! ¡DESPIERTA AHORA MISMO!`;
      voiceName = 'Fenrir'; // More energetic
      break;
    case 'normal':
    default:
      promptText = `¡Despierta! Estás llegando a ${locationName}.`;
      voiceName = 'Zephyr';
      break;
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: promptText }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    throw new Error("Falló la generación de audio");
  }
  return base64Audio;
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  MapPin, Navigation, Bell, Search, StopCircle, Volume2, 
  AlertCircle, RefreshCw, Loader2, ArrowLeft, X, User, 
  Settings, Heart, Trash2, History, ChevronRight, Zap, Smartphone, Check
} from 'lucide-react';
import { LineChart, Line, YAxis, ResponsiveContainer } from 'recharts';
import { findLocation, generateAlarmAudio, getPlaceSuggestions } from './services/gemini';
import { calculateDistance, formatDistance } from './utils/geo';
import { AppStatus, LocationInfo, AlarmConfig, Coordinates, SavedPlace, AlarmSettings, AlarmIntensity } from './types';
import MapDisplay from './components/MapDisplay';

const App: React.FC = () => {
  // State
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const [locationError, setLocationError] = useState<string | null>(null);
  const [currentLocation, setCurrentLocation] = useState<Coordinates | null>(null);
  const [useHighAccuracy, setUseHighAccuracy] = useState(true); // Preference

  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig | null>(null);
  const [distanceHistory, setDistanceHistory] = useState<{ distance: number; time: number }[]>([]);
  const [currentDistance, setCurrentDistance] = useState<number | null>(null);

  // Persistence State
  const [savedPlaces, setSavedPlaces] = useState<SavedPlace[]>([]);
  const [history, setHistory] = useState<SavedPlace[]>([]);

  // Alarm Settings
  const [alarmSettings, setAlarmSettings] = useState<AlarmSettings>({
    volume: 100,
    vibration: true,
    intensity: 'normal'
  });

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const vibrationIntervalRef = useRef<number | null>(null);
  const watchIdRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const debounceRef = useRef<number | null>(null);

  // Load from LocalStorage
  useEffect(() => {
    const loadedPlaces = localStorage.getItem('napnav_places');
    const loadedHistory = localStorage.getItem('napnav_history');
    const loadedSettings = localStorage.getItem('napnav_settings');

    if (loadedPlaces) setSavedPlaces(JSON.parse(loadedPlaces));
    if (loadedHistory) setHistory(JSON.parse(loadedHistory));
    if (loadedSettings) setAlarmSettings(JSON.parse(loadedSettings));
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem('napnav_places', JSON.stringify(savedPlaces));
  }, [savedPlaces]);

  useEffect(() => {
    localStorage.setItem('napnav_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('napnav_settings', JSON.stringify(alarmSettings));
  }, [alarmSettings]);

  // Initialize Audio Context
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  // Geolocation Watcher
  useEffect(() => {
    if ('geolocation' in navigator) {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
      }

      console.log(`Iniciando observador de geolocalización. Alta Precisión: ${useHighAccuracy}`);

      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          const newLocation = {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          };
          setCurrentLocation(newLocation);
          setLocationError(null);
        },
        (error) => {
          // Fallback logic handled here only if actively tracking or showing map
          if (error.code === 3 && useHighAccuracy) {
             console.log("Timeout alta precisión -> Fallback.");
             // Optional: setUseHighAccuracy(false) automatic fallback
          }
          let msg = "Ubicación no disponible.";
           switch (error.code) {
            case 1: msg = "Permiso denegado."; break;
            case 2: msg = "Sin señal GPS."; break;
            case 3: msg = "Tiempo agotado."; break;
          }
          setLocationError(msg);
        },
        { 
          enableHighAccuracy: useHighAccuracy, 
          maximumAge: 10000, 
          timeout: 30000 
        }
      );
    } else {
      setLocationError("Navegador no soportado.");
    }

    return () => {
      if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
    };
  }, [useHighAccuracy]);

  // Autocomplete
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (query.trim().length > 2 && status === AppStatus.IDLE) {
      setIsSuggesting(true);
      debounceRef.current = window.setTimeout(async () => {
        try {
          const results = await getPlaceSuggestions(query, currentLocation);
          setSuggestions(results);
          setShowSuggestions(true);
        } catch (e) {
          console.error("Falló el autocompletado", e);
        } finally {
          setIsSuggesting(false);
        }
      }, 500); 
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
      setIsSuggesting(false);
    }

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [query, currentLocation, status]);

  // Distance Tracking
  useEffect(() => {
    if (status !== AppStatus.TRACKING || !currentLocation || !alarmConfig) return;

    const dist = calculateDistance(currentLocation, alarmConfig.target);
    setCurrentDistance(dist);

    setDistanceHistory((prev) => {
      const newData = [...prev, { distance: dist, time: Date.now() }];
      return newData.slice(-20);
    });

    if (dist <= alarmConfig.radius) {
      triggerAlarm();
    }
  }, [currentLocation, status, alarmConfig]);

  // Wake Lock
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {
      console.log('Error Wake Lock:', err);
    }
  };

  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.log('Error al liberar Wake Lock', err);
      }
    }
  }, []);

  // --- Logic Functions ---

  const executeSearch = async (searchQuery: string, radiusOverride?: number) => {
    if (!searchQuery.trim()) return;

    setStatus(AppStatus.SEARCHING);
    setShowSuggestions(false);
    try {
      const location = await findLocation(searchQuery);
      // Pass intensity setting to audio generation
      const audioBase64 = await generateAlarmAudio(location.name, alarmSettings.intensity);

      setAlarmConfig({
        target: location,
        radius: radiusOverride || 500, 
        audioBase64: audioBase64
      });
      setStatus(AppStatus.CONFIRMING);
    } catch (error) {
      console.error(error);
      alert("No pudimos encontrar ese lugar. Inténtalo de nuevo.");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(query);
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    executeSearch(suggestion);
  };

  const startTracking = async () => {
    if (!alarmConfig) return;
    initAudio();
    await requestWakeLock();

    // Add to history
    const newHistoryItem: SavedPlace = {
      ...alarmConfig.target,
      id: Date.now().toString(),
      dateAdded: Date.now(),
      defaultRadius: alarmConfig.radius
    };
    // Keep last 10 items, remove duplicates by name
    setHistory(prev => {
      const filtered = prev.filter(p => p.name !== newHistoryItem.name);
      return [newHistoryItem, ...filtered].slice(0, 10);
    });

    setStatus(AppStatus.TRACKING);
  };

  const stopTracking = async () => {
    setStatus(AppStatus.IDLE);
    setDistanceHistory([]);
    setCurrentDistance(null);
    stopAlarmSound();
    stopVibration();
    setQuery(''); 
    await releaseWakeLock();
  };

  const triggerAlarm = () => {
    setStatus(AppStatus.ALARM_TRIGGERED);
    playAlarmSound();
    startVibration();
  };

  const playAlarmSound = async () => {
    if (!alarmConfig?.audioBase64 || !audioContextRef.current) return;
    try {
      const binaryString = atob(alarmConfig.audioBase64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const buffer = await audioContextRef.current.decodeAudioData(bytes.buffer);

      const play = () => {
        // Create Gain Node for volume
        const gainNode = audioContextRef.current!.createGain();
        // Volume 0-100 mapped to 0-1 gain
        gainNode.gain.value = alarmSettings.volume / 100;
        gainNode.connect(audioContextRef.current!.destination);

        const source = audioContextRef.current!.createBufferSource();
        source.buffer = buffer;
        source.connect(gainNode);
        source.start(0);
        source.onended = () => {
            if (status === AppStatus.ALARM_TRIGGERED) { /* loop handled by source.loop */ }
        };
        source.loop = true; 
        audioSourceRef.current = source;
      };
      play();
    } catch (e) {
      console.error("Fallo en reproducción de audio", e);
    }
  };

  const stopAlarmSound = () => {
    if (audioSourceRef.current) {
      audioSourceRef.current.stop();
      audioSourceRef.current = null;
    }
  };

  const startVibration = () => {
    if (!alarmSettings.vibration || !('vibrate' in navigator)) return;

    // Pattern based on intensity
    let pattern: number[] = [];
    let interval = 1000;

    switch (alarmSettings.intensity) {
        case 'soft':
            pattern = [200, 1000]; // Short pulse, long pause
            interval = 1200;
            break;
        case 'intense':
            pattern = [500, 100, 500, 100]; // Urgent pulsing
            interval = 1200;
            break;
        case 'normal':
        default:
            pattern = [500, 500];
            interval = 1000;
            break;
    }

    const vibrate = () => navigator.vibrate(pattern);
    vibrate(); // First one
    vibrationIntervalRef.current = window.setInterval(vibrate, interval);
  };

  const stopVibration = () => {
    if (vibrationIntervalRef.current) {
        clearInterval(vibrationIntervalRef.current);
        vibrationIntervalRef.current = null;
    }
    if ('vibrate' in navigator) navigator.vibrate(0);
  };

  const toggleSavedPlace = (place: LocationInfo) => {
    const exists = savedPlaces.find(p => p.name === place.name && p.lat === place.lat);
    if (exists) {
      setSavedPlaces(prev => prev.filter(p => p.id !== exists.id));
    } else {
      const newPlace: SavedPlace = {
        ...place,
        id: Date.now().toString(),
        dateAdded: Date.now()
      };
      setSavedPlaces(prev => [newPlace, ...prev]);
    }
  };

  const isSaved = (place: LocationInfo | undefined) => {
    if (!place) return false;
    return savedPlaces.some(p => p.name === place.name && p.lat === place.lat);
  };

  const deleteSavedPlace = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSavedPlaces(prev => prev.filter(p => p.id !== id));
  };

  // --- UI RENDERERS ---

  const renderIdle = () => (
    <div className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0 z-0 opacity-25 blur-[2px] pointer-events-none grayscale brightness-110">
        <MapDisplay center={{ lat: -34.9011, lng: -56.1645 }} zoom={13} />
        <div className="absolute inset-0 bg-gradient-to-b from-white/60 via-white/40 to-white/60"></div>
      </div>

      {/* Top Bar */}
      <div className="absolute top-0 left-0 right-0 p-6 flex justify-end z-20">
        <button 
          onClick={() => setStatus(AppStatus.PROFILE)}
          className="bg-white/80 backdrop-blur-md p-3 rounded-full shadow-sm hover:bg-white transition-all text-gray-700"
        >
          <User className="w-6 h-6" />
        </button>
      </div>

      <div className="relative z-10 flex flex-col items-center w-full px-6">
        <div className="bg-blue-100 p-4 rounded-full mb-6 shadow-sm">
          <MapPin className="w-12 h-12 text-blue-600" />
        </div>
        <h1 className="text-4xl font-black text-gray-900 mb-2 tracking-tight">NapNav</h1>
        <p className="text-gray-700 font-medium text-center mb-10 max-w-xs drop-shadow-sm">
          Duerme en tu viaje. Te despertaremos cuando estés cerca.
        </p>

        <div className="w-full max-w-md relative group">
          <form onSubmit={handleSearch} className="w-full relative z-20">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
              placeholder="¿A dónde vas?"
              className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-gray-200/80 bg-white/90 backdrop-blur-sm focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none text-lg shadow-lg text-gray-900 placeholder:text-gray-400"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-6 h-6" />

            {isSuggesting ? (
              <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 animate-spin" />
            ) : (
              <button 
                  type="submit" 
                  disabled={!query}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl font-medium disabled:opacity-50 hover:bg-blue-700 transition-colors shadow-md"
              >
                  Ir
              </button>
            )}
          </form>

          {/* Autocomplete */}
          {showSuggestions && suggestions.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white/95 backdrop-blur-md rounded-xl shadow-xl border border-gray-100 overflow-hidden z-30 animate-in fade-in slide-in-from-top-2 duration-200">
              <ul className="divide-y divide-gray-50">
                {suggestions.map((item, idx) => (
                  <li key={idx}>
                    <button
                      onClick={() => handleSuggestionClick(item)}
