                <div className="text-7xl font-black tracking-tighter mb-2 text-transparent bg-clip-text bg-gradient-to-b from-white to-slate-400 drop-shadow-[0_0_15px_rgba(99,102,241,0.5)]">
                    {currentDistance !== null ? formatDistance(currentDistance) : '...'}
