const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Tarea 1: findLocation
 * Procesa una búsqueda (incluso informal) y devuelve coordenadas estructuradas.
 */
export const findLocation = async (query: string): Promise<LocationInfo> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act as a geocoding expert. The user is searching for a location, possibly using informal language (e.g., "the bus stop near the mall"). 

    User Query: "${query}"

    1. Interpret the user's intent to find the specific physical location.
    2. Return the best estimated Latitude and Longitude.
    3. Return a clean Name and a short Address (in Spanish).

    Return ONLY JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER, description: "Latitude in decimal degrees" },
          lng: { type: Type.NUMBER, description: "Longitude in decimal degrees" },
          name: { type: Type.STRING, description: "Official name of the place" },
          address: { type: Type.STRING, description: "Short address in Spanish" },
        },
        required: ["lat", "lng", "name"],
      },
    },
