/**
 * Tarea 1: generateAlarmAudio
 * Genera un script personalizado según intensidad y lo convierte a audio usando Gemini TTS.
 */
export const generateAlarmAudio = async (locationName: string, intensity: AlarmIntensity = 'normal'): Promise<string> => {
  let promptText = "";
  let voiceName = 'Zephyr';

  // Configuración de guiones y voces según intensidad
  switch (intensity) {
    case 'soft':
      promptText = `Disculpa, ya estamos cerca de ${locationName}. Es hora de ir despertando suavemente.`;
      voiceName = 'Kore'; // Voz más suave/femenina
      break;
    case 'intense':
      promptText = `¡ATENCIÓN! ¡DESPIERTA! ¡Ya llegamos a ${locationName}! ¡Levántate ahora!`;
      voiceName = 'Fenrir'; // Voz más grave/enérgica
      break;
    case 'normal':
    default:
      promptText = `¡Despierta! Estamos llegando a ${locationName}.`;
      voiceName = 'Zephyr'; // Voz balanceada
      break;
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: promptText }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    throw new Error("Falló la generación de audio TTS");
  }

  return base64Audio;
};

import { Coordinates } from '../types';

/**
 * Tarea 2: calculateDistance
 * Calcula la distancia en metros entre dos coordenadas usando la fórmula de Haversine.
 * R = 6371e3 (Radio de la Tierra en metros)
 */
export const calculateDistance = (coord1: Coordinates, coord2: Coordinates): number => {
  if (!coord1 || !coord2) return Infinity;

  const R = 6371e3; // Radio de la tierra en metros
  const lat1 = (coord1.lat * Math.PI) / 180;
  const lat2 = (coord2.lat * Math.PI) / 180;
  const deltaLat = ((coord2.lat - coord1.lat) * Math.PI) / 180;
  const deltaLng = ((coord2.lng - coord1.lng) * Math.PI) / 180;

  const a =
    Math.sin(deltaLat / 2) * Math.sin(deltaLat / 2) +
    Math.cos(lat1) * Math.cos(lat2) * Math.sin(deltaLng / 2) * Math.sin(deltaLng / 2);

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c; // Devuelve distancia en metros
};

export const formatDistance = (meters: number): string => {
  if (meters < 1000) {
    return `${Math.round(meters)}m`;
  }
  return `${(meters / 1000).toFixed(2)}km`;
};

